"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[63271],{71148(e,i,t){t.r(i),t.d(i,{assets:()=>c,contentTitle:()=>o,default:()=>f,frontMatter:()=>r,metadata:()=>n,toc:()=>d});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/curing-of-a-credit-impaired-financia-59893ce139","title":"Curing of a Credit-impaired Financial Asset (IFRS 9)","description":"March 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/Curing of a Credit-impaired Financial Asset (IFRS 9).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/curing-of-a-credit-impaired-financia-59893ce139","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/curing-of-a-credit-impaired-financia-59893ce139","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"curing-of-a-credit-impaired-financia-59893ce139","title":"Curing of a Credit-impaired Financial Asset (IFRS 9)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/curing-of-a-credit-impaired-financia-59893ce139","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Credit Enhancement in the Measurement of Expected CreditLosses (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/credit-enhancement-in-the-measuremen-7083a6f464"},"next":{"title":"Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/fair-value-hedge-of-foreign-currency-25afdd6d0e"}}');var a=t(74848),s=t(28453);let r={id:"curing-of-a-credit-impaired-financia-59893ce139",title:"Curing of a Credit-impaired Financial Asset (IFRS 9)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/curing-of-a-credit-impaired-financia-59893ce139",sidebar_position:2},o="Curing of a Credit-impaired Financial Asset (IFRS 9)",c={},d=[];function l(e){let i={blockquote:"blockquote",h1:"h1",header:"header",p:"p",strong:"strong",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(i.header,{children:(0,a.jsx)(i.h1,{id:"curing-of-a-credit-impaired-financial-asset-ifrs-9",children:"Curing of a Credit-impaired Financial Asset (IFRS 9)"})}),"\n",(0,a.jsx)(i.p,{children:"March 2019"}),"\n",(0,a.jsx)(i.p,{children:"The Committee received a request about how an entity presents amounts recognised in the statement of profit or loss when a credit-impaired financial asset is subsequently cured (ie paid in full or no longer credit-impaired)."}),"\n",(0,a.jsx)(i.p,{children:"When a financial asset becomes credit-impaired, paragraph 5.4.1(b) of IFRS 9 requires an entity to calculate interest revenue by applying the \u2018effective interest rate to the amortised cost of the financial asset\u2019. This results in a difference between (a) the interest that would be calculated by applying the effective interest rate to the gross carrying amount of the credit-impaired financial asset; and (b) the interest revenue recognised for that asset. The request asked whether, following the curing of the financial asset, an entity can present this difference as interest revenue or, instead, is required to present it as a reversal of impairment losses."}),"\n",(0,a.jsx)(i.p,{children:"Appendix A to IFRS 9 defines a credit loss as \u2018the difference between all contractual cash flows that are due to an entity in accordance with the contract and all the cash flows that the entity expects to receive (ie all cash shortfalls), discounted at the original effective interest rate\u2026\u2019. Appendix A also defines the gross carrying amount as \u2018the amortised cost of a financial asset, before adjusting for any loss allowance.\u2019 The Committee noted that, based on the definitions in Appendix A to IFRS 9, the gross carrying amount, amortised cost and loss allowance are discounted amounts, and changes in these amounts during a reporting period include the effect of the unwinding of the discount."}),"\n",(0,a.jsx)(i.p,{children:"Paragraph 5.5.8 of IFRS 9 requires an entity to \u2018recognise in profit or loss, as an impairment gain or loss, the amount of expected credit losses (or reversal) that is required to adjust the loss allowance at the reporting date to the amount that is required to be recognised in accordance with this Standard.\u2019"}),"\n",(0,a.jsx)(i.p,{children:"The Committee observed that, applying paragraph 5.5.8 of IFRS 9, an entity recognises in profit or loss as a reversal of expected credit losses the adjustment required to bring the loss allowance to the amount that is required to be recognised in accordance with IFRS 9 (zero if the asset is paid in full). The amount of this adjustment includes the effect of the unwinding of the discount on the loss allowance during the period that the financial\nasset was credit-impaired, which means the reversal of impairment losses may exceed the impairment losses recognised in profit or loss over the life of the asset."}),"\n",(0,a.jsx)(i.p,{children:"The Committee also observed that paragraph 5.4.1 specifies how an entity calculates interest revenue using the effective interest method. Applying paragraph 5.4.1(b), an entity calculates interest revenue on a credit-impaired financial asset by applying the effective interest rate to the amortised cost of the financial asset, and thus interest revenue on such a financial asset does not include the difference described in the request."}),"\n",(0,a.jsx)(i.p,{children:"Accordingly, the Committee concluded that, in the statement of profit or loss, an entity is required to present the difference described in the request as a reversal of impairment losses following the curing of a credit-impaired financial asset."}),"\n",(0,a.jsx)(i.p,{children:"The Committee concluded that the requirements in IFRS Standards provide an adequate basis for an entity to recognise and present the reversal of expected credit losses following the curing of a credit-impaired financial asset in the fact pattern described in the request. Consequently, the Committee decided not to add this matter to its standard-setting agenda."}),"\n",(0,a.jsxs)(i.blockquote,{children:["\n",(0,a.jsxs)(i.p,{children:[(0,a.jsx)(i.strong,{children:"Educational Material"}),"\nEducational material relating to the Committee's conclusion in this agenda decision is>available on the IFRS 9 supporting materials page."]}),"\n"]})]})}function f(e={}){let{wrapper:i}={...(0,s.R)(),...e.components};return i?(0,a.jsx)(i,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},28453(e,i,t){t.d(i,{R:()=>r,x:()=>o});var n=t(96540);let a={},s=n.createContext(a);function r(e){let i=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(i):{...i,...e}},[i,e])}function o(e){let i;return i=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),n.createElement(s.Provider,{value:i},e.children)}}}]);